// AmelisoServiceServer is the server API for AmelisoService service.
// All implementations must embed UnimplementedAmelisoServiceServer
// for forward compatibility.
//
// AmelisoService manages test cases, suites, and runs stored in PostgreSQL.
// All operations accept a repo_id identifying the connected GitHub repository (full_name, e.g. "owner/repo").
//
// Recommended agent workflow (minimum 3 RPCs):
//
//	Step 1 — CreateRun(commit_sha=<HEAD>, use_last_run=true)
//	  Auto-scopes to cases affected since the last completed run.
//	  On the first ever run (no prior run) all cases are included.
//	  Response: pending (Case.body + latest_status), total_repo_cases,
//	  uncovered_files (source files with no test case).
//
//	Optional Step 1b — if uncovered_files is non-empty:
//	  BulkCreateCases(cases=[...], run_id=run.id)
//	  Creates cases for coverage gaps AND adds them to the current run's scope.
//	  Response: file_paths (for git add), pending (updated with new cases).
//
//	Step 2 — BulkRecordResults — record all results in one call.
//	  Response: pending (remaining cases), pending_count, total_in_scope.
//
//	Step 3 — FinalizeRun(status=UNSPECIFIED)
//	  Auto-detects ABORTED if any FAILED result, else COMPLETED.
//	  Response: run (RunMeta with counts), results (all CaseResult records).
//
// Repeat from step 1 on the next commit.
//
// Additional zero-extra-RPC data available in responses:
//
//	GetRun        — cases field (Case list with body; no separate ListCases call needed)
//	ListRuns      — RunMeta.passed/failed/blocked/skipped/total counts per run
//	RecordResult  — pending field (remaining cases after this result)
//	GetRepoStatus — last_completed_run (RunMeta with counts)
//	UpdateRun     — add_cases to extend run scope; commit_sha/testers/environment patches
//	GetAffectedCases — cases (body + latest_status) + uncovered_files (coverage gaps)
//
// For richer context before running (stats, active runs), call GetRepoStatus first.
// For a read-only preview of affected cases, call GetAffectedCases instead of CreateRun.
type AmelisoServiceServer interface {
	// --- Cases ---
	ListCases(context.Context, *ListCasesRequest) (*ListCasesResponse, error)
	GetCase(context.Context, *GetCaseRequest) (*GetCaseResponse, error)
	GetCaseHistory(context.Context, *GetCaseHistoryRequest) (*GetCaseHistoryResponse, error)
	CreateCase(context.Context, *CreateCaseRequest) (*CreateCaseResponse, error)
	BulkCreateCases(context.Context, *BulkCreateCasesRequest) (*BulkCreateCasesResponse, error)
	UpdateCase(context.Context, *UpdateCaseRequest) (*UpdateCaseResponse, error)
	BulkUpdateCases(context.Context, *BulkUpdateCasesRequest) (*BulkUpdateCasesResponse, error)
	DeleteCase(context.Context, *DeleteCaseRequest) (*DeleteCaseResponse, error)
	BulkDeleteCases(context.Context, *BulkDeleteCasesRequest) (*BulkDeleteCasesResponse, error)
	RestoreCase(context.Context, *RestoreCaseRequest) (*RestoreCaseResponse, error)
	// --- Suites ---
	ListSuites(context.Context, *ListSuitesRequest) (*ListSuitesResponse, error)
	GetSuite(context.Context, *GetSuiteRequest) (*GetSuiteResponse, error)
	CreateSuite(context.Context, *CreateSuiteRequest) (*CreateSuiteResponse, error)
	UpdateSuite(context.Context, *UpdateSuiteRequest) (*UpdateSuiteResponse, error)
	DeleteSuite(context.Context, *DeleteSuiteRequest) (*DeleteSuiteResponse, error)
	RestoreSuite(context.Context, *RestoreSuiteRequest) (*RestoreSuiteResponse, error)
	// --- Runs ---
	ListRuns(context.Context, *ListRunsRequest) (*ListRunsResponse, error)
	GetRun(context.Context, *GetRunRequest) (*GetRunResponse, error)
	CreateRun(context.Context, *CreateRunRequest) (*CreateRunResponse, error)
	RecordResult(context.Context, *RecordResultRequest) (*RecordResultResponse, error)
	BulkRecordResults(context.Context, *BulkRecordResultsRequest) (*BulkRecordResultsResponse, error)
	FinalizeRun(context.Context, *FinalizeRunRequest) (*FinalizeRunResponse, error)
	DeleteRun(context.Context, *DeleteRunRequest) (*DeleteRunResponse, error)
	RestoreRun(context.Context, *RestoreRunRequest) (*RestoreRunResponse, error)
	GetPendingCases(context.Context, *GetPendingCasesRequest) (*GetPendingCasesResponse, error)
	// Rename a run's slug (date prefix is preserved). Returns the updated run metadata.
	UpdateRun(context.Context, *UpdateRunRequest) (*UpdateRunResponse, error)
	// --- Reports ---
	// Coverage for all cases; sorted failed/never first then by priority. Optional status_filter.
	GetCoverageReport(context.Context, *GetCoverageReportRequest) (*GetCoverageReportResponse, error)
	// Return cases affected by source changes since since_ref (uses GitHub compare API).
	// Sorted failed/never first then by priority — same ordering as GetPendingCases.
	GetAffectedCases(context.Context, *GetAffectedCasesRequest) (*GetAffectedCasesResponse, error)
	// Aggregate snapshot: case counts by priority, coverage counts, suite/run totals, active runs with pending counts.
	GetRepoStatus(context.Context, *GetRepoStatusRequest) (*GetRepoStatusResponse, error)
	// --- Testers ---
	// Returns suggested tester names from run history and GitHub contributors.
	GetTesterSuggestions(context.Context, *GetTesterSuggestionsRequest) (*GetTesterSuggestionsResponse, error)
	// --- GitHub App ---
	GetGitHubInstallUrl(context.Context, *GetGitHubInstallUrlRequest) (*GetGitHubInstallUrlResponse, error)
	HandleGitHubCallback(context.Context, *HandleGitHubCallbackRequest) (*HandleGitHubCallbackResponse, error)
	ListRepositories(context.Context, *ListRepositoriesRequest) (*ListRepositoriesResponse, error)
	SyncRepository(context.Context, *SyncRepositoryRequest) (*SyncRepositoryResponse, error)
	RemoveRepository(context.Context, *RemoveRepositoryRequest) (*RemoveRepositoryResponse, error)
	// Generate a new API key for the given repository (rotates any existing key).
	RotateRepoApiKey(context.Context, *RotateRepoApiKeyRequest) (*RotateRepoApiKeyResponse, error)
	// Append-only log of destructive actions (delete case/run/suite).
	ListAuditLog(context.Context, *ListAuditLogRequest) (*ListAuditLogResponse, error)
	mustEmbedUnimplementedAmelisoServiceServer()
}

